import{c as l,W as t,j as o,m as i}from"./chunks/framework.CoQR5MuA.js";const c=JSON.parse('{"title":"Lands Act赞比亚土地法","description":"赞比亚国情资料 — Lands Act赞比亚土地法","frontmatter":{"title":"Lands Act赞比亚土地法","description":"赞比亚国情资料 — Lands Act赞比亚土地法"},"headers":[],"relativePath":"mining/zambia/zh/land-law-notes.md","filePath":"mining/zambia/zh/land-law-notes.md","lastUpdated":1780402543000}'),a={name:"mining/zambia/zh/land-law-notes.md"};function s(r,p,n,u,g,e){return t(),o("div",null,[...p[0]||(p[0]=[i('<h1 id="lands-act赞比亚土地法" tabindex="-1">Lands Act赞比亚土地法 <a class="header-anchor" href="#lands-act赞比亚土地法" aria-label="Permalink to &quot;Lands Act赞比亚土地法&quot;">​</a></h1><div class="reading-prose"><p>赞比亚法律</p><p>版权所有 赞比亚共和国法律事务部</p><p>赞比亚共和国土地法</p><p>土地法案 第184章</p><p>第184章 土地法</p><p>目录</p><p>第一章</p><p>初步条款</p><p>简称</p><p>解释</p><p>第二章</p><p>土地管理</p><ul><li><ol start="3"><li>所有土地归总统所有</li></ol></li><li><ol start="4"><li>土地转让条件</li></ol></li><li><ol start="5"><li>总统的同意</li></ol></li><li><ol start="6"><li>地方议会持有的土地的归还</li></ol></li><li><ol start="7"><li>认可传统土地保有权</li></ol></li><li><ol start="8"><li>将传统保有权转换为租赁保有权</li></ol></li><li><ol start="9"><li>禁止未经授权占用土地</li></ol></li><li><ol start="10"><li>租约续期</li></ol></li><li><ol start="11"><li>地租及承租人契约与条件的利益</li></ol></li><li><ol start="12"><li>租赁分割后条件的分摊</li></ol></li><li><ol start="13"><li>重新进入证明书应登记</li></ol></li><li><ol start="14"><li>地租的支付及逾期支付的罚款</li></ol></li><li><ol start="15"><li>土地纠纷向土地仲裁庭申请</li></ol></li></ul><p>第三章</p><p>土地发展基金</p><ul><li><ol start="16"><li>土地发展基金</li></ol></li><li><ol start="17"><li>基金的管理</li></ol></li><li><ol start="18"><li>基金的资金使用</li></ol></li><li><ol start="19"><li>收支报表</li></ol></li></ul><p>第四章</p><p>土地仲裁庭</p><ul><li><ol start="20"><li>土地仲裁庭</li></ol></li><li><ol start="21"><li>评估员</li></ol></li><li><ol start="22"><li>仲裁庭的管辖权</li></ol></li><li><ol start="23"><li>仲裁庭的程序</li></ol></li><li><ol start="24"><li>规则</li></ol></li><li><ol start="25"><li>法律代表</li></ol></li><li><ol start="26"><li>轻率和骚扰性诉讼</li></ol></li><li><ol start="27"><li>仲裁庭的费用</li></ol></li><li><ol start="28"><li>秘书和会计</li></ol></li><li><ol start="29"><li>上诉</li></ol></li></ul><p>第五章</p><p>一般规定</p><ul><li><ol start="30"><li>现有利益和权利的保留</li></ol></li><li><ol start="31"><li>法规</li></ol></li><li><ol start="32"><li>废除Cap. 289和附表中的法律</li></ol></li></ul><p>附表</p><p>土地法案 第184章</p><p>土地</p><p>本法案旨在规定租赁保有权和租赁地产权的持续存在；规定土地继续归总统所有，并由总统进行土地转让；规定法定认可和持续存在的习惯保有权；规定将习惯保有权转换为租赁保有权；建立土地发展基金和土地仲裁庭；废除《土地（所有权转换）法案》；废除1928年至1964年的赞比亚（国家土地和保留地）命令、1947年至1964年的赞比亚（信托土地）命令、1959年至1964年的赞比亚（格温贝区）命令，以及1970年的西方省（土地及其他条款）法案；并规定与前述事项相关或附带的事项。</p><p><strong>第一<strong><strong>章</strong></strong> 初步****条款</strong></p><p>本法案可被称为《土地法》。</p><p>在本法案中，除非上下文另有要求，以下解释适用：</p><p>&quot;所有权证书&quot; 指根据《土地与契约登记法案》颁发的土地所有权证书；</p><p>&quot;习惯区域&quot; 指，尽管有第三十二节的规定，但在1928年至1964年的《赞比亚（国家土地和保留地）命令》和1947年至1964年的《赞比亚（信托土地）命令》的附表中描述的区域；</p><p>&quot;基金&quot; 指根据第十六节设立的土地发展基金；</p><p>&quot;改进&quot; 指任何因资本或劳动支出而产生的结果，并包括在土地上、上、下或下进行的任何建筑、工程或其他操作，或对任何建筑物或土地使用方式进行的任何实质性改变，以及在土地开发或发展过程中提供的服务费用和其他费用；</p><p>&quot;土地&quot; 指任何土地利益，无论土地是原始的、光秃的还是有改进的，但不包括根据《矿山和矿产法案》对任何土地定义的任何采矿权；</p><p>&quot;租赁&quot; 指由总统授予的租赁或根据废除的法案从自由保有权转换而来的租赁，&quot;承租人&quot;应相应解释；</p><p>&quot;永久居民&quot; 指一个已建立的居民或持有根据《移民和驱逐法案》的入境许可的人；</p><p>&quot;临时所有权证书&quot; 指根据《土地与契约登记法案》颁发的临时土地所有权证书；</p><p>&quot;注册官&quot; 指在《土地与契约登记法案》中赋予其意义的人； Cap. 185</p><p>&quot;废除的法案&quot; 指《土地（所有权转换）法案》； Cap. 289 1972年版</p><p>&quot;国家土地&quot; 指不位于习惯区域的土地；</p><p>&quot;仲裁庭&quot; 指根据第十九节设立的土地仲裁庭。</p><p><strong>第二章 土地管理</strong></p><p>(1) 尽管任何其他法律、文书或文件中包含的任何内容相反，但根据本法案，赞比亚所有土地应绝对归总统所有，并应由他永久持有，代表赞比亚人民的利益。 所有土地归总统所有</p><p>(2) 根据第(4)款和任何其他法律的规定，总统可以将归其所有的土地转让给任何赞比亚人。</p><p>(3) 根据有关土地转让的其他规定和程序，总统可以在以下情况下将土地转让给非赞比亚人：</p><p>(a) 当非赞比亚人是赞比亚共和国的永久居民时；</p><p>(b) 当非赞比亚人是根据《投资法》或与赞比亚投资促进有关的任何其他法律意义上的投资者时；</p><p>(c) 当非赞比亚人获得了总统的书面同意；</p><p>(d) 当非赞比亚人是根据《公司法》注册的公司，且非赞比亚人拥有的已发行股份少于百分之二十五；</p><p>(e) 当非赞比亚人是由议会法案设立的法定公司；</p><p>(f) 当非赞比亚人是根据《合作社法》注册的合作社，且非赞比亚成员少于百分之二十五；</p><p>(g) 当非赞比亚人是根据《土地（永久继承）法》注册的机构，并且是一个非营利的、慈善的、宗教的、教育的或慈善的组织或机构，且已注册并经部长批准用于本节的目的；</p><p>(h) 当所涉利益或权利源于租赁、转租或低于租赁，期限不超过五年，或租约协议；</p><p>(i) 当土地利益或权利因死亡而继承或根据生存权或法律行为转移；</p><p>(j) 当非赞比亚人是根据《公司法》和《银行和金融服务法》注册的商业银行；或</p><p>(k) 当非赞比亚人根据《国家公园和野生动物法》获得特许权或权利。</p><p>(4) 尽管第(3)款有规定，总统不得转让位于习惯保有制地区的任何土地：</p><p>(a) 未考虑与本法案不冲突的地方习惯土地保有法；</p><p>(b) 未与土地所在地区酋长和地方当局协商，在游戏管理区，以及国家公园和野生动物服务局的局长，他们应确定要转让的土地；</p><p>(c) 未与可能受到授予影响的任何其他人或机构协商；</p><p>(d) 如果申请租赁地产权的人未获得土地所在地区酋长和地方当局的事先批准。</p><p>(5) 根据本法案或任何其他法律，赞比亚的所有土地应由总统管理或控制，用于赞比亚人民的使用或直接或间接的共同利益。</p><p>(6) 总统不得根据第(2)款或第(3)款转让任何土地，期限超过九十九年，除非：</p><p>(a) 总统认为出于国家利益或履行共和国的任何义务是必要的；</p><p>(b) 经国民议会三分之二多数成员批准。</p><p>(7) 在转让土地时，总统应采取必要措施：</p><p>(a) 控制定居点、耕作方法和土地利用，以保护该土地上的自然资源；</p><p>(b) 为森林保护区、游戏管理区和国家公园留出土地，并发展和控制这些保护区、游戏管理区和国家公园。</p><p>(1) 总统在转让第(2)款或第(3)款第3节下的土地时，不得在未收到该转让的任何金钱形式的对价和该土地的地租的情况下转让，除非转让是出于公共目的：</p><p>(2) 在本节中，“公共目的”包括以下内容：</p><p>(a) 仅供政府使用或赞比亚人民普遍利益；</p><p>(b) 与任何类型的卫生改善有关，包括填海；</p><p>(c) 与规划任何新的市镇或扩大或改善任何现有市镇有关；</p><p>(d) 与航空有关；</p><p>(e) 为根据立法授权建造的任何铁路建设；</p><p>(f) 为获得对政府随时建造或打算建造的任何铁路、道路或其他公共工程邻近土地的控制权；</p><p>(g) 为获得对与水力发电或其他电力发电和供应目的有关的土地的控制权；</p><p>(h) 与保护、保育、开发或控制森林产物、动物、植物、土壤、水和其他自然资源有关。</p><p>(1) 任何人不得在未获得总统同意的情况下出售、转让或许让任何土地，并应在这样做之前申请该同意。</p><p>总统的同意</p><p>(2) 如果一个人根据第(1)款申请同意，且在提交申请后45天内未获同意，则应视为已获同意。</p><p>(3) 如果总统在30天内拒绝同意，他应给出拒绝的理由。</p><p>(4) 对总统拒绝同意的决定不满的人，可在拒绝之日起30天内上诉至土地仲裁庭寻求救济。</p><p>(1) 除第(2)款规定外，所有由地方议会持有的土地，包括已转租的土地，租期为99年或更短，根据本法案，无需进一步保证或许可，应视为已归还给总统，并且转租人应被视为持有该土地，好像总统直接授予了租约。</p><p>(2) 除第(3)款规定外，第(1)款所述的转租人应被视为根据授予地方议会的租约的条件和契约持有土地，但承租人应按照法定文书规定的年度地租支付给总统。</p><p>(3) 第(1)款不适用于地方议会为自己的使用而持有的土地，或根据《住房（法定改进区）法案》持有的土地。</p><p>(4) 本法案生效时，经支付规定的费用后，注册官应在登记册的相关页上批注本节的效果。</p><p>(1) 尽管第32条第(2)款有规定，但根据第9条，本法案生效前立即在习惯区域归任何人所有或由任何人持有的每块土地，应继续以习惯保有权持有并得到认可，本法案或任何其他法律的任何规定均不得被解释为侵犯该人在本法案生效前享有的任何习惯权利。</p><p>(2) 尽管第32条有规定，任何人根据习惯法持有土地的权利和特权应得到认可，任何人根据适用于其已定居或打算定居地区的习俗法持有土地，不应被解释为违反本法案或任何其他法律的任何规定，除非可能根据赞比亚的任何其他法律产生的权利或义务。</p><p>(1) 尽管第7节有规定，但在本法案生效后，任何持有习惯保有权土地的人都可以通过申请，按照规定的方式，将其转换为不超过99年的租赁保有权：</p><p>(a) 总统授予的租赁保有权；</p><p>(b) 总统可能授予的任何其他所有权；</p><p>(c) 任何其他法律。</p><p>(2) 从习惯保有权到租赁保有权的权利转换，只有在所在地区酋长和地方当局的批准下才能生效，如果涉及游戏管理区，还需国家公园和野生动物服务局的局长批准，要转换的土地应通过计划图准确显示转换土地的范围。</p><p>(3) 除了赞比亚任何其他法律可能产生的权利外，除非经过酋长确认，并且总统授予了租赁，否则任何所有权，除了个人根据习惯保有权对土地的使用和占有权外，都应视为无效。</p><p>(1) 任何人不得在没有法律授权的情况下占用或继续占用空地。</p><p>(2) 任何违反第(1)款占用土地的人都可能被驱逐。</p><p>(1) 如果总统满意地认为承租人已经遵守或许可了租约的条款、条件或许诺，并且租约没有被没收的风险，他应将租约在到期后更新，更新期限不超过99年。</p><p>(2) 如果总统不更新租约，承租人有权根据《土地（征用）法案》规定的程序，对其在土地上所做的改进获得赔偿。</p><p>(1) 尽管有关于可继承产业的分割，地租以及租约或任何有关租约事项的议会法案中包含的每个契约或条款的利益，都应附属并附带于可继承产业，以及立即期待租约授予的期限的土地或产业的任何部分。</p><p>地租和承租人契约的利益</p><p>(2) 总统或包含在任何议会法案中的条件或契约所产生的义务，应附属并附带于可继承产业或该产业的几个部分，尽管该产业被分割，并且可以通过转让、法律上的转移或其他方式由拥有期限的人执行。</p><p>(3) 第(1)款不妨碍任何要求承租人遵守或履行契约的契约、租约或议会法案以及每个重新进入的条件。</p><p>(1) 除授予中固定的地租外，租约中的每个重新进入的权利、每个其他条件以及除地租外的任何其他条款，应按照如下方式分摊，就好像每个分割的部分或剩余期限的土地，或在租约中包含的土地上，原本就单独包含在租约中一样，尽管：</p><p>(a) 通过分配、转让、交还或以其他方式分割了租约中包含的任何土地的可继承产业；</p><p>(b) 租约授予的期限仅对租约中包含的土地部分以其他方式被撤销或终止。</p><p>(2) 根据第(1)款提到的每个重新进入的权利或条件，应保持对可继承产业的分割部分附属，就好像每个分割部分是可继承的，或者土地的部分在该期限尚未交还或已被撤销或尚未以这种方式终止，就好像在每个分割部分或剩余期限的土地上，或在该期限仍然有效的土地上，原本就单独包含在租约中一样。</p><p>(1) 如果承租人违反了本法案下的租约条款或条件，总统应给予承租人三个月的通知，说明他打算在注册簿上登记重新进入的证明，要求承租人陈述为什么不应该在注册簿上登记重新进入的证明。</p><p>(2) 如果承租人在三个月内未按照第(1)款的要求进行陈述，或者在进行陈述后总统不满意，认为承租人违反条款或条件是故意的或超出了承租人的控制，他可以使重新进入的证明在注册簿上登记。</p><p>(3) 对总统决定在注册簿上登记重新进入证明感到不满的承租人，可在决定之日起三十天内上诉至土地仲裁庭，要求下令更正注册簿。</p><p>(1) 承租人应支付总统规定的地租。</p><p>地租的支付及逾期支付的罚款</p><p>(2) 在第(3)款规定的条件下，如果任何地租金额在第(1)款规定的到期日后仍未支付，承租人应对未付的地租支付25%的罚款。</p><p>(1) 任何对权力部门的指示或决定不满的人，都可以向土地仲裁庭申请裁定。</p><p>(2) 在本节中，“权力部门”指的是总统、部长或注册官。</p><p><strong>第三章</strong></p><p><strong>土地发展基金</strong></p><p>(1) 特此设立土地发展基金。</p><p>(2) 基金应由以下资金组成：</p><p>(a) 议会为基金目的而拨出的款项；</p><p>(b) 第四节下支付的款项的75%；</p><p>(c) 从所有土地收集的地租的50%。</p><p>基金应归负责财政的部长所有，并由负责土地的部长管理和行政。</p><p>基金的管理</p><p>(1) 第十七节所述的部长应将基金的款项用于开发土地的新领域的开拓。</p><p>基金款项的用途</p><p>(2) 希望在其地区开发任何地区的理事会，可以向基金申请资金以开发该地区。</p><p>第十七节所述的部长应编制年度收支报表，并提交给国民议会。</p><p><strong>第四章</strong></p><p><strong>土地仲裁庭</strong></p><p>(1) 特此设立土地仲裁庭。</p><p>(2) 仲裁庭应由以下成员组成，由部长任命：</p><p>(a) 有资格成为高等法院法官的主席；</p><p>(b) 有资格被任命为高等法院法官的副主席；</p><p>(c) 总检察长办公室的律师；</p><p>(d) 注册城市规划师；</p><p>(e) 注册土地测量师；</p><p>(f) 注册估价测量师；</p><p>(g) 来自公共和私营部门的不超过三人。</p><p>(3) 第(2)款(a)项和(b)项所述的成员应在与司法服务委员会协商后任命。</p><p>(4) 仲裁庭的成员应在其任命信中规定的条款和条件下任命。</p><p>仲裁庭可以任命具有土地、农业、商业或其他相关职业资格的能力和经验的人担任评估员，以协助其根据本法案确定任何事项。</p><p>仲裁庭应具有管辖权：</p><p>(a) 调查并就本法案下与土地有关的任何争议作出裁决和决定；</p><p>(b) 调查并就本法案下支付的任何补偿争议作出裁决和决定；</p><p>(c) 一般地调查并裁决根据本法案影响任何人或政府的土地权利和义务的任何事项；</p><p>(d) 执行根据本法案或任何其他书面法律规定的任何行为和职责。</p><p>(1) 仲裁庭的会议应由主席或副主席主持。</p><p>(2) 仲裁庭在审理任何事项时，如果由五名成员组成，包括主席或副主席，应被视为适当组成。</p><p>(3) 仲裁庭对任何事项的裁决应根据考虑该事项的多数成员的意见作出。</p><p>(4) 如果仲裁庭或评估员在仲裁庭面前的任何事项中有直接或间接、个人或金钱的利益，则不得参加仲裁庭的听证。</p><p>(5) 仲裁庭不受民事诉讼中适用的证据规则的约束。</p><p>首席大法官可以通过法定文书制定规则：</p><p>(a) 规范仲裁庭的程序；</p><p>(b) 规定在仲裁庭前传唤和出庭的证人以及出示任何文件或其他证据的程序。</p><p>在仲裁庭前作为一方出现的人员可以亲自出庭或由法律执业者代表，费用自理。</p><p>如果仲裁庭满意，任何向仲裁庭的申请是轻率或骚扰性的，它可以命令申请人支付其费用、另一方的费用以及与诉讼有关的政府费用。</p><p>仲裁庭的费用和开支应由议会为此目的拨款支付。</p><p>负责法律事务的部门应向仲裁庭提供必要的秘书和会计协助，以使其能够根据本法案履行职能。</p><p>对仲裁庭的任何裁决、声明或决定不满的任何人，可在三十天内向最高法院上诉。</p><p><strong>第五章</strong></p><p><strong>一般规定</strong></p><p>除本法案其他条款的规定外，本法案中的任何内容均不得影响在本法案生效之前已创建、授予、认可或承认的任何法律或衡平法上的地产、权利或利益。</p><p>(1) 部长可以通过法定文书制定规章，以更好地执行本法案的规定。</p><p>(2) 特别是，但不影响第(1)款的一般性，此类规章可以规定：</p><p>(a) 租约的条款、条件和契约；</p><p>(b) 申请总统对任何交易的同意的程序，该交易涉及或影响土地；</p><p>(c) 将习惯保有权转换为租赁保有权的程序；</p><p>(d) 申请租约续期的程序；</p><p>(e) 土地的地租；</p><p>(f) 土地交易的费用；</p><p>(g) 本法案或任何其他书面法律规定的任何其他事项。</p><p>(1) 《土地（所有权转换）法案》被正式废除。</p><p>(2) 如附表中列出的法律被正式废除。</p><p><strong>附表</strong></p><p><strong>(第32节)</strong></p><p><strong>被废除的法律：</strong></p><p>《赞比亚（国家土地和保留地）命令》，1928年至1964年。</p><p>《赞比亚（信托土地）命令》，1947年至1964年。</p><p>《赞比亚（格温贝区）命令》，1959年至1964年。</p><p>《西方省（土地及其他条款）法案》，1970年。</p><p><strong>附属立法</strong></p><p>第31条 - 《土地（土地发展基金）》</p><p>部长制定的法规</p><p>法定文书88号，1996年</p><p>第一章 初步条款</p><p>这些法规可被称为《土地（土地发展基金）法规》。</p><p>在这些法规中，除非上下文另有要求，以下解释适用：</p><p>&quot;主席&quot; 指委员会的主席；</p><p>&quot;委员会&quot; 指第3条设立的土地发展基金委员会；</p><p>&quot;基金&quot; 应与法案中的含义相同；</p><p>&quot;部长&quot; 指负责土地的部长，</p><p>&quot;部门&quot; 应相应解释；</p><p>&quot;秘书&quot; 指根据第3条任命的秘书。</p><p>第二部分 从基金中分配资金</p><ul><li><ol start="3"><li>(1) 特此设立土地发展基金委员会，其职能是考虑并决定从基金中分配资金的申请。</li></ol></li></ul><p>土地发展基金委员会</p><p>(2) 委员会由以下成员组成：</p><p>(a) 部门的常任秘书，担任主席；</p><p>(b) 土地专员，担任副主席；</p><p>(c) 负责地方政府和住房的部门的一名高级官员；</p><p>(d) 赞比亚地方政府协会的一名官员；</p><p>(e) 负责农业的部门的土地利用规划科的一名官员；</p><p>(f) 负责环境的部门的一名代表；</p><p>(g) 部门的首席会计师；</p><p>(h) 负责财政的部门的一名会计师。</p><p>(3) 如果部长认为有必要这样做，他可以额外任命最多两名官员参加委员会。</p><p>(4) 第2款(c)项、(g)项和(h)项提到的成员应由他们所代表的部长或部门提名。</p><p>(5) 应有一名基金秘书，由部长任命。</p><ul><li><ol start="4"><li>(1) 任何希望从基金中申请资金以发展其地区的地区的理事会，可以向秘书申请资金发展该地区：</li></ol></li></ul><p>前提是，基金的资金只能用于实施那些私营部门无法提供的开发项目。</p><p>(2) 根据第1款提到的申请应以书面形式提出，并应包含以下细节：</p><p>(a) 开发建议的详细情况；</p><p>(b) 开发建议将实施的城镇和省份的名称；</p><p>(c) 理事会希望承担的开发估计成本；</p><p>(d) 显示开发建议主题土地的位置和公顷数的图表或草图；</p><p>(e) 开发建议的实施计划；以及</p><p>(f) 开发的未来运营和维护计划，以及开发将如何获得资金。</p><p>(1) 主席应在收到根据第4条由秘书提交的申请后的三十天内，召集会议考虑该申请。</p><p>(2) 委员会应决定：</p><p>(a) 理事会的开发建议是否可以接受和可行；</p><p>(b) 开发建议是否需要在提交给部长前进行修改；</p><p>(c) 开发建议是否证明所请求的资金是合理的；</p><p>(d) 所请求的资金是否可以一次性或分期发放；</p><p>(e) 开发建议可能在多长时间内实施。</p><p>(3) 如果委员会发现开发建议是可行和可接受的，委员会应向部长推荐从基金中拨款，并应在推荐中包括：</p><p>(a) 请求拨款的理事会的名称；</p><p>(b) 开发建议；</p><p>(c) 所需资金的金额；</p><p>(d) 委员会的发现。</p><p>(4) 部长在考虑委员会的建议时可以：</p><p>(a) 接受建议；或</p><p>(b) 拒绝建议。</p><p>(5) 如果部长</p><p>(a) 根据第4款接受委员会的建议，部长应立即书面通知秘书，并应与负责财政的部长协商，向相关理事会发放资金；或</p><p>(b) 拒绝委员会的建议，部长应立即书面通知秘书。</p><p>(6) 秘书应在部长做出决定后的七天内，书面通知相关理事会该决定。</p><p>向理事会从基金中分配资金应通过支票或银行转账方式进行。</p><p>(1) 根据第6条的规定从基金中收到资金的理事会，应立即在其选择的银行开立一个单独的银行账户，该账户中只存放从基金转移的资金。</p><p>(2) 根据第1款提到的账户应称为&quot;土地发展基金账户&quot;，并应包含开立账户的理事会的名称。</p><p>(1) 收到资金的理事会，每三个月以及在拟议开发的实施结束时，应向秘书提交有关拟议项目的报告。</p><p>(2) 根据第1款提到的报告应包括：</p><p>(a) 收入和支出的报表；</p><p>(b) 是否需要更多资金的说明；以及</p><p>(c) 未来需求的预测。</p><p>基金应每年进行审计。</p><p><strong>其他条款</strong></p><p>委员会应负责监督和评估基金资金的使用情况。</p><p>如果有证据表明理事会滥用或挪用了基金资金，委员会可以向部长建议：</p><p>(a) 冻结理事会的银行账户，等待调查；</p><p>(b) 在提交报告之前，负责财政的部门不再向理事会发放更多资金；</p><p>(c) 对被认定为滥用或挪用资金的个人提起刑事诉讼。</p><p>任何滥用或挪用基金资金的个人均构成犯罪，一经定罪，可处以不超过两千七百七十八罚金单位的罚款，或不超过三个月的监禁，或两者并罚。</p><p>第31条 - 《土地（习惯保有权）（转换）法规》</p><p>第1节</p><p>这些法规可被称为《土地（习惯保有权）（转换）法规》。</p><p>第2节</p><p>(1) 以下人员可以申请将习惯保有权转换为租赁保有权：</p><p>(a) 根据习惯保有权对土地有使用和占有权的人；</p><p>或</p><p>(b) 在习惯区域使用和占有土地，并打算在那里定居至少五年的人；</p><p>可以向土地所在地地区的酋长提交附表中列出的表格一申请转换。</p><p>(2) 酋长应考虑申请并给予或拒绝同意。</p><p>(3) 如果酋长拒绝同意，他应以附表中列出的表格二的形式通知申请人和土地专员，并说明拒绝同意的理由。</p><p>(4) 如果酋长同意申请，他应以附表中列出的表格二的形式确认：</p><p>(a) 申请人对土地有使用和占有权；</p><p>(b) 申请人根据习惯保有权持有土地的时间；</p><p>(c) 申请人没有侵犯他人权利；</p><p>并将表格转交给土地所在地区的地方议会。</p><p>第3节</p><p>(1) 地方议会在收到第2条第(4)款提到的表格后，在向土地专员提出建议之前，应考虑该地区的习惯法与法案是否存在冲突。</p><p>(2) 如果地方议会确信该地区的习惯法与法案没有冲突，地方议会应以附表中列出的表格三的形式向土地专员提出建议。</p><p>土地专员应接受或拒绝接受建议，并向申请人通报情况。</p><p>第4节</p><p>如果地方议会认为将特定地块从习惯保有权转换为租赁保有权符合社区利益，地方议会应与土地所在地的酋长协商，向土地专员申请转换。</p><p>(2) 在提出第(1)款所述的申请之前，地方议会应：</p><p>(a) 查明与要转换的土地相关的任何家庭或社区利益或权利；</p><p>(b) 明确任何将授予租赁保有权的权益或权利的条件。</p><p>第5节</p><p>将土地从习惯保有权转换为租赁保有权后，持有该土地的个人应按照土地专员规定的数额，支付该土地的年度地租。</p><p>第6节</p><p>对土地专员的决定不满的个人可以向土地仲裁庭提出上诉。</p><p>附表</p><p>(第2条和第3条)</p><p>表格一</p><p>(第2条)</p><p>申请将习惯保有权转换为租赁保有权的申请表</p><p>申请人详细信息：</p><p>姓名 ..........................................................................</p><p>邮政和实际地址： ..............................................................</p><p>土地位置： ....................................................................</p><p>土地面积和计划编号： ...........................................................................</p><p>权利声明： (a) 我或我的家庭对计划图上显示的土地拥有使用和占有权，连续期为 ................................................................................................................... 年； (b) 我对土地享有权益，并且我不知道除了： ................................................................................................................... 之外，还有任何其他人对土地或土地部分拥有使用或占有权； 并且授予我租赁保有权将不会影响这些权利。 签名： ................................................................ 日期： ......................................................................................................</p><p>注：</p><p>(i) 如果占用时间少于五年，请描述土地的使用和占有是如何开始的，说明允许您占用和使用土地的酋长或头人的姓名；</p><p>(ii) 通过描述土地的用途，证明土地的使用和占有是排他的；</p><p>(iii) 请将六份土地布局图附在此表格上。</p><p>表格二</p><p>(第2条)</p><p>酋长对将习惯保有权转换为租赁保有权的申请的批准</p><p>................................................................................................... 村庄的酋长 确认并证明：</p><ul><li><p>1.我已经调查了 ...................................................................................................... 的使用和占有权（申请人将被调查，调查揭示了申请人或他的家庭在过去 年中一直在占用计划图中描述的土地，我在该计划书上签名）。</p></li><li><p>2.我不知道除了这些权利外，还有任何其他个人或共同体对土地或土地的任何部分拥有使用和占有权，除了这些权利一直由社区享有，并且不会影响申请人对土地的使用和占有权。</p></li><li><p>3.我已经与社区成员进行了协商。</p></li><li><p>4.根据协商和提供给我的信息，我特此给予/拒绝我对将该土地转换为租赁保有权的批准。</p></li></ul><p>签名： ................................................................ 日期： ......................................................................................................</p><p>表格三</p><p>(第3条)</p><p>地方当局对将习惯保有权转换为租赁保有权的批准</p><p>我， ......................................................................................................................，作为 ............................................................................................................................................................................... 区议会的议会秘书，确认并声明：()财产编号) .............................................................................................................................................. 将要由申请人 .......................................................................................................................... 从习惯保有权转换为租赁保有权的土地位于 ...................................................................................................................................................................... 区议会的边界内。</p><p>并且该土地位于 ...................................................................................................................... 酋长的管辖范围内。酋长对土地从习惯保有权转换为租赁保有权的批准/拒绝书附在此。</p><p>申请人 .................................................................................................... （姓名）已连续占用并拥有对该土地的使用和占有权，连续期为 .............................................................................. 年。</p><p>我不知道除了这些权利外，还有任何其他个人或共同体对土地或土地的任何部分拥有使用和占有权。</p><p>根据提供给我的信息，我特此给予/拒绝我对将该土地转换为租赁保有权的批准。</p><p>签名： ................................................................ 日期： ......................................................................................................</p><p>第24节 - 土地（土地仲裁庭）规则</p><p>规则由首席大法官制定</p><p>法定文书90号，1996年</p><p>第一部分 初步条款</p><p>第1条</p><p>这些规则可被称为土地仲裁庭规则。</p><p>第2条</p><p>在这些规则中，除非上下文另有要求，以下解释适用：</p><p>&quot;成员&quot; 指仲裁庭的成员；</p><p>&quot;诉讼&quot; 指在仲裁庭前的诉讼；</p><p>&quot;秘书处&quot; 指法案中提到的秘书处；</p><p>&quot;办公室&quot; 指土地仲裁庭的当前办公室。</p><p>第二部分 仲裁庭的诉讼程序</p><p>第3条</p><p>(1) 对任何指示或决定提出上诉，可通过向秘书处发送一式两份的书面上诉通知来启动，该通知应说明：</p><p>(a) 上诉人和被上诉人的姓名和地址；</p><p>(b) 指示或决定的日期、参考号码和细节；</p><p>(c) 土地或产权的描述，包括适当的土地位置图；</p><p>(d) 上诉人要求仲裁庭确定的问题，包括必要时上诉人要求仲裁庭确定的金额或价值数额的声明；</p><p>(e) 上诉理由；</p><p>(f) 上诉人是否不打算传唤专家证人作证；</p><p>(g) 上诉人接收服务或通知及其他文件的地址；</p><p>(h) 审理上诉所必需的其他信息。</p><p>(2) 除非上诉通知书在指示或决定送达上诉人之日起三十日内提交给秘书处，或者根据赋予上诉权的法规规定的其他时间内提交，否则上诉通知书无效。</p><p>第4条</p><p>(1) 收到上诉通知书后，秘书处应：</p><p>(a) 在上诉登记册中记录上诉的详情；</p><p>(b) 将副本通知发送给被上诉人，并告知上诉人和被上诉人上诉在登记册中的参考号码，此后该号码将构成上诉的标题。</p><p>(2) 收到副本上诉通知书后，被上诉人应将决定的副本发送给秘书处。</p><p>第5条</p><p>(1) 主席可以根据需要，在收到上诉通知书后随时要求提供进一步和更好的细节，说明他打算依靠的理由以及任何相关的事实和论点。</p><p>(2) 上述声明应在主席指示的时间内一式两份提交给秘书处，不得少于要求之日起十四天，并将副本发送给秘书处可能确定的与同一诉讼有关的其他提出上诉的人。</p><p>(3) 收到第(2)款所述的声明后，秘书处应将副本声明发送给被上诉人。</p><p>第6条</p><p>如果主席要求被上诉人提供任何似乎对决定上诉必要的决定细节，被上诉人应将这些细节提供给秘书处和上诉人。</p><p>第7条</p><p>(1) 如果仲裁庭根据法案第22条的规定任命了一名评估员协助其决定任何事项，秘书处应以书面形式通知任何被任命的评估员，并告知其听证的地点和日期。</p><p>(2) 任何评估员应得的报酬应由主席与负责财政的部长批准后确定。</p><p>第8条</p><p>(1) 仲裁庭应在主席决定的地方和时间开庭。</p><p>(2) 秘书处应向仲裁庭前的每一方发送通知，告知听证的地点和日期，除非各方另有约定，否则不得早于通知送达之日起十四天后。</p><p>(3) 任何根据第(2)款收到通知的人，可以根据第19条规定，向秘书处申请更改听证的地点或日期。</p><p>第9条</p><p>仲裁庭应公开开庭，除非任何一方申请，仲裁庭指示全部或部分诉讼应闭门举行。</p><p>第10条</p><p>(1) 仲裁庭可对诉讼所涉及的土地或产权进行检查，并可在认为合适的情况下进入土地或产权进行检查。</p><p>(2) 除非仲裁庭提前七日通知各方其意图，否则不得进入任何场所，各方应出席检查。</p><p>第11条</p><p>(1) 如果秘书处收到涉及同一土地或产权的多个上诉通知，任何一方可申请命令合并上诉。</p><p>(2) 秘书处可在认为公正的情况下根据第(1)款合并上诉。</p><p>(3) 仲裁庭可在认为合适的情况下，仅就上诉通知所涉及的部分事项作出命令。</p><p>第12条</p><p>(1) 仲裁庭前的证据可以口头提供，或者如果各方同意或仲裁庭主席下令，也可以通过宣誓书提供。</p><p>(2) 仲裁庭在诉讼的任何阶段可下令要求任何宣誓陈述人亲自出庭接受审查和交叉审问。</p><p>第13条</p><p>诉讼的一方应在秘书处要求时向秘书处提供任何文件或其他信息，这些是仲裁庭可能需要且该方有能力提供的，并向每一方提供机会以检查这些文件或其副本并取得文件副本：</p><p>前提是本规则中的任何内容都不应被解释为要求披露与公共利益相反的任何信息。</p><p>第14条</p><p>如果仲裁庭认为任何一方未能根据这些规则向任何其他方或秘书处提供任何文件副本，仲裁庭可指示发送必要的文件副本，并可将诉讼的进一步听证延期，并在任何此类情况下要求有过错的一方支付由此失败引起的任何额外费用。</p><p>第15条</p><p>在上诉听证时，上诉人不得依赖其上诉通知中未声明的任何理由，除非仲裁庭认为公正，并在认为合适的成本或延期或其他条件下。</p><p>第16条</p><p>(1) 在任何诉讼中，一方可以亲自出庭，或通过律师，或通过为此目的指定的任何其他人，并获得仲裁庭的同意，或在当局的情况下，由为此目的指定的官员出庭。</p><p>第17条</p><p>(1) 除非这些规则另有规定，与任何诉讼有关的任何临时性指示申请，除非主席另有命令，应向秘书处提出。</p><p>(2) 上述申请应以书面形式提出，并应说明诉讼的标题和申请的理由。</p><p>(3) 如果申请是经所有方同意提出的，应附上由各方或代表各方签署的同意书。</p><p>(4) 如果申请不是经每一方同意提出的，那么在提出申请之前，应将副本送达给每一其他方，并且申请应说明已经这样做了。</p><p>(5) 反对申请的一方可以在副本送达之日起14天内向秘书处发出书面反对通知，并抄送给申请人。</p><p>(6) 在对申请作出决定之前，秘书处应考虑所有收到的反对意见，并且如果任何一方希望被听取，秘书处应给予他和每一其他方这样的机会。</p><p>(7) 秘书处可以，如果申请人或根据本规则对该申请提出异议的一方要求，将申请提交给主席决定。</p><p>(8) 对秘书处根据本规则作出的申请决定不满的一方，可以在送达决定通知之日起14天内向秘书处和每一其他方发出书面上诉通知，并由主席决定。</p><p>(9) 除非主席下令，否则秘书处的决定上诉不暂停诉讼程序。</p><p>(10) 主席根据本规则的权力和职责可以由主席授权的任何仲裁庭成员行使和履行。</p><p>第18条</p><p>秘书处有权为在诉讼中使用的宣誓书的目的而管理宣誓和接受确认。</p><p>第19条</p><p>根据这些规则指定的或根据这些规则进行的任何行为或步骤的时间，可以根据按照这些规则向秘书处提出的申请，在案件的公正可能要求的任何条件下被延长，即使申请可能在指定时间之后提出，也可以下令延长。</p><p>第20条</p><p>(1) 主席可以根据任何一方的申请，命令在仲裁庭的初步听证会上处理诉讼中出现的任何法律问题。</p><p>(2) 如果仲裁庭认为，法律问题的决定实质上解决了诉讼，仲裁庭可以命令将诉讼视为案件的听证，或作出其他公正的命令。</p><p>第21条</p><p>(1) 上诉可以通过向秘书处发送书面撤回通知来撤回，该通知由所有诉讼方或其律师或代理人签署。</p><p>(2) 上诉人可以在诉讼听证前随时向主席申请下令驳回诉讼，主席随后可以作出公正的命令。</p><p>(3) 如果任何一方未能遵守这些规则的任何规定，主席可以在给予各方被听取的机会后，下令仲裁庭听证诉讼，或作出其他适当的命令，以加快或处理诉讼。</p><p>第22条</p><p>(1) 如果在上诉审理时，上诉人或诉讼的其他一方未在指定的时间和地点出庭，仲裁庭可以：</p><p>(a) 驳回上诉；</p><p>(b) 在其缺席的情况下审理并决定上诉，并可就费用作出其认为合适的命令：</p><p>前提是，如果在一方缺席的情况下根据本规则驳回或决定诉讼，该方可以在驳回或决定之日起十四天内申请仲裁庭撤销驳回或决定，并说明其未出席听证的原因。</p><p>(2) 如果仲裁庭满意根据第(1)款规定提供的原因是足够的，以撤销驳回或决定，仲裁庭可以撤销该驳回或决定。</p><p>第24条</p><p>(1) 仲裁庭对上诉的决定应以书面形式给出，并附上仲裁庭作出决定的理由说明。</p><p>(2) 秘书处应在决定作出之日起十四天内，向每位在仲裁庭前出现的当事人发送决定副本。</p><p>第25条</p><p>如果诉讼各方已就仲裁庭将作出的任何命令条款达成一致，应将条款详情，由所有方或其律师或代理人签署，送交秘书处，仲裁庭可在当事人缺席的情况下根据这些条款作出命令。</p><p><strong>第三章 一般条款</strong></p><p>第26条</p><p>(1) 仲裁庭可授予其认为必要的费用。</p><p>(2) 当仲裁庭指示诉讼一方的费用应由任何其他方支付时，仲裁庭可以确定一个总金额来结算费用，或者可以指示秘书处根据高等法院规则规定的费用标准来核算费用。</p><p>(3) 任何对仲裁庭指示的费用核算不满的一方，可以在核算之日起七天内，向任何其他利益相关方和秘书处提交书面异议，明确指出反对的项目和反对的理由，并申请对这些项目进行费用核算复审。</p><p>(4) 如果根据第(3)款提出异议，秘书处应复审所反对项目的核算，并以书面形式说明其决定的理由。</p><p>(5) 如果任何一方对秘书处根据第(4)款作出的决定不满，可以在决定之日起十四天内向主席申请复审费用核算，主席可以作出他认为公正的命令，包括命令支付复审的费用，但对于未提出异议的所有事项，核算将是最终决定。次性支付，或者可以指示秘书处根据高等法院规则规定的费用表进行费用核算。</p><p>第27条</p><p>(1) 任何根据这些规则需要或授权送达给任何人的通知书或其他文件，如果通过注册邮件发送到该人根据这些规则给出的通常服务地址，应被视为已经适当送达。</p><p>(2) 任何向主席或仲裁庭任何成员提出的申请或沟通，应向秘书处提出。</p><p>第28条</p><p>(1) 如果任何一方当事人更改了地址，他应通过向秘书处和诉讼的其他每一方提供书面通知，告知秘书处和当事人这些变更。</p><p>第29条</p><p>如果任何需要为这些规则目的发送通知或其他文件的人无法找到，或者已经去世且没有个人代表，或者不在赞比亚，或者由于任何其他原因无法根据这些规则轻易送达，仲裁庭主席可以下令以主席认为合适的其他人员或形式替代送达。</p><p>第30条</p><p>任何人未能遵守这些规则的规定，不使诉讼程序或根据诉讼程序采取的任何行动无效，除非仲裁庭主席如此指示。</p><p><strong>第31节 - 土地（地租和费用）法规</strong></p><p><strong>由部长制定的法规</strong></p><p>这些法规可以被称为《土地（地租和费用）法规》。</p><p>(2) 第一附表中列出的地租应由持有该附表中指定土地的人支付。</p><p>(3) 第二和第三附表中列出的费用应支付，与该附表中指定的土地交易有关。</p><p>第一附表</p><p>(第2条)</p><p>除农业用地外的土地应付的地租</p><p>第一部分</p><p>土地描述 每公顷或部分的年租金</p><p>**1.**<strong>卢萨卡</strong></p><p>住宅地块</p><p>(a) 高成本 K50,000</p><p>卡布隆加 宾贝（桑宁代尔）伍德兰兹 罗马 卡皮拉（罗兹公园）楚德利 耶斯蒙丁 奇瓦拉 马布韦（奥林匹克公园）朗阿克雷斯 马卢巴（费尔维尤）奇孔托（北米德）卡伦杜 切尔斯通 格林 马德拉斯</p><p>(b) 中等成本 K30,000</p><p>阿冯代尔 伍德兰兹延伸 恰昆库拉（切尔斯通）卢内塔（索恩公园）纳蒙古纳（维拉伊丽莎白）</p><p>(c) 未在(a)和(b)中指定的任何其他区域 K15,000</p><p>(d) 位于卢萨卡市中心五公里内的商业和工业地块 K100,000</p><p>任何其他商业和工业地块 K40,000</p><p>教堂、福利厅、童子军和女童军厅及牧师住宅 K20,000</p><p>俱乐部会所、运动场、体育场、公共设施等 K30,000</p><p><strong>恩多拉</strong></p><p>住宅地块</p><p>(a) 高成本 K40,000</p><p>诺思莱兹 卡森申希 伊陶瓦</p><p>(b) 中等成本 K20,000</p><p>卡尼尼 希尔克雷斯特</p><p>(c) 未在(a)和(b)中指定的任何其他区域 K10,000</p><p>(d) 位于恩多拉市中心五公里内的商业和工业地块 K75,000</p><p>任何其他商业和工业地块 K40,000</p><p>教堂、福利厅、童子军和女童军厅及牧师住宅 K20,000</p><p>俱乐部会所、运动场、体育场、公共设施等 K30,000</p><p><strong>基特韦</strong></p><p>住宅地块</p><p>(a) 高成本 K40,000</p><p>河滨公园</p><p>(b) 中等成本 K20,000</p><p>河滨延伸 布亚坦希 恩德克村</p><p>**卡布韦、穆富利拉、利文斯通、卢安沙、钦戈拉、奇拉博姆韦和卡卢卢希。 **</p><p>住宅用地 20,000克瓦查</p><p>商业用地 40,000克瓦查</p><p>工业用地 40,000克瓦查</p><p>教堂、福利大厅、童子军和女童军大厅以及牧师住所 20,000克瓦查</p><p>俱乐部会所、运动场、体育场、公共设施等 20,000克瓦查</p><p>未在上述第一部分和第二部分中指定的其他地区议会。</p><p>住宅用地 15,000克瓦查</p><p>商业用地 20,000克瓦查</p><p>工业用地 15,000克瓦查</p><p>教堂、福利大厅、童子军和女童军大厅以及牧师住所 15,000克瓦查</p><p>俱乐部会所、运动场、体育场、公共设施等 20,000克瓦查</p><p>卢萨卡、恩多拉和基特韦市中心20公里范围内的农业用地（包括小农场）的年度地租： (a) 不超过五十公顷：首公顷三万克瓦查，之后每公顷或其部分五千克瓦查； (b) 超过五十公顷但不超过一百公顷：按照(a)中五十公顷的租金加上每增加一公顷或其部分四千克瓦查； (c) 超过一百公顷但不超过二百五十公顷：按照(b)中五十公顷的租金加上每增加一公顷或其部分二千克瓦查； (d) 超过二百五十公顷：按照(c)中二百五十公顷的租金加上每增加一公顷或其部分一千五百克瓦查。</p><p>未在第四部分中指定的农业用地（包括小农场）的年度地租： (a) 不超过一百公顷：首公顷或其部分二万克瓦查，之后每公顷或其部分二百五十克瓦查； (b) 超过一百公顷但不超过二百五十公顷：按照(a)中的规定，加上每增加一公顷或其部分五百克瓦查； (c) 超过二百五十公顷：按照(b)中二百五十公顷的租金，加上每增加一公顷或其部分一千克瓦查。</p><p>位于矿区的土地，年度地租应为每公顷或其部分五千克瓦查。 在从传统土地转为正式土地的过程中，应付的地租和费用应为地租和费用的一半。</p><p>第二附表</p><p>(第3条)</p><p>文件准备应付的费用和收费：</p><p>费用 单位</p><p>卢萨卡市议会内土地的租赁费 278</p><p>恩多拉和基特韦市议会内土地的租赁费 166</p><p>未在(2)中指定的市议会内土地的租赁费 111</p><p>卢萨卡市议会内土地文件的准备费 111</p><p>与2和3中所述相符的土地文件的准备费 56</p><p>交还费 56</p><p>租约到期证明书 56</p><p>取消重新进入证明书 278</p><p>租约协议 556</p><p>修正契约 111</p><p>使协会或组织能够持有土地的公司注册证书 167</p><p>根据申请人要求对土地进行检查 556</p><p>与土地有关的宣誓书起草 (a) 适用于国家土地内的 111 (b) 适用于习惯土地内的 28</p><p>未特别提及的任何土地交易文件的准备 89</p><p>向议会或土地部门申请土地的申请表 56</p><p>根据申请人要求对土地进行检查 556</p><p>准备将习惯保有权转换为租赁保有权的文件 28</p><p>第三附表</p><p>(第3条)</p><p>每个人应为根据第5节提出的每次申请同意书支付三百三十三个费用单位作为申请费，用于分配、出售、转让或类似申请。</p><p>每个人应为同意书的每次续期支付第1款规定的费用。</p><p>土地费用规定</p><p>这些规章可以被引用为《土地（费用）规章》。</p><p>在该附表中规定的费用，应支付给在附表中指定的土地交易。</p><p>附表</p><p>(第2条)</p><p>土地交易费用表</p><p>费用单位</p><p>市议会区域内土地的租约准备费用 111</p><p>市政委员会区域内土地的租约准备费用 83</p><p>区议会区域内土地的租约准备费用 56</p><p>将习惯保有权转换为租赁保有权的文件准备费用 28</p><p>交还费用 56</p><p>租约终止证明书 278</p><p>重新进入取消证明书 56</p><p>土地检查（应申请人要求） 556</p><p>修正契约 56</p><p>租约协议 556</p><p>土地宣誓书起草费用： (a) 适用于国家土地内的 111 (b) 适用于习惯土地内的 28</p><p>协会或组织持有土地的公司注册证书 278</p><p>根据第5条申请同意书出售、转让或指定的申请 278</p><p>同意书出售、转让或指定的续期 278</p><p>向议会或土地部门申请土地的申请表 56</p><p>任何未特别提及的土地交易文件的准备 89</p></div>',2)])])}const d=l(a,[["render",s]]);export{c as __pageData,d as default};
